from typing import List

def separate_paren_groups(paren_string: str) -> List[str]:
    result = []
    count = 0
    current_group = ''

    for char in paren_string:
        if char == '(':
            count += 1
            current_group += char
        elif char == ')':
            count -= 1
            current_group += char
            if count == 0:
                result.append(current_group.replace(' ', ''))
                current_group = ''

    return result

def get_odd_collatz(n):
    def collatz(num):
        sequence = [num]
        while num != 1:
            if num % 2 == 0:
                num = num // 2
            else:
                num = 3 * num + 1
            sequence.append(num)
        return sequence

    collatz_sequence = collatz(n)
    odd_numbers = sorted(set(filter(lambda x: x % 2 != 0, collatz_sequence)))
    return odd_numbers

